import{c as a,cG as s,cb as e,c8 as t,cf as l,cT as i,ce as n}from"./chunks/framework.BlkIsu1j.js";const r=JSON.parse('{"title":"角色转变与局限","description":"","frontmatter":{"title":"角色转变与局限","outline":"deep","layout":"doc","prev":"/ai/claudecode/05-workflows","next":"/ai/claudecode/cheatsheet","date":"2026-05-20T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecode/06-mindset.md","filePath":"ai/claudecode/06-mindset.md","lastUpdated":1779211503000}'),d={id:"frontmatter-title",tabindex:"-1"};const o=a({name:"ai/claudecode/06-mindset.md"},[["render",function(a,r,o,p,h,c){return s(),e("div",null,[t("h1",d,[l(i(a.$frontmatter.title)+" ",1),r[0]||(r[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),r[1]||(r[1]=n('<p>工具在进化，使用工具的人也需要进化。本章探讨使用 Claude Code 后带来的角色变化、心态调整，以及需要正视的局限性。</p><h2 id="角色转变-从-coder-到-orchestrator" tabindex="-1">角色转变：从 Coder 到 Orchestrator <a class="header-anchor" href="#角色转变-从-coder-到-orchestrator" aria-label="Permalink to “角色转变：从 Coder 到 Orchestrator”">​</a></h2><h3 id="旧模式-vs-新模式" tabindex="-1">旧模式 vs 新模式 <a class="header-anchor" href="#旧模式-vs-新模式" aria-label="Permalink to “旧模式 vs 新模式”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>旧模式：</span></span>\n<span class="line"><span>  思考 → 编码 → 调试 → 测试 → 提交</span></span>\n<span class="line"><span>  (你完成所有环节)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>新模式：</span></span>\n<span class="line"><span>  思考 → 描述 → 审查 → 引导 → 提交</span></span>\n<span class="line"><span>  (Claude 执行编码/调试/测试，你负责方向和审查)</span></span></code></pre></div><p>你的核心能力从 <strong>&quot;写得快&quot;</strong> 转变为 <strong>&quot;想得清&quot;</strong>：</p><table tabindex="0"><thead><tr><th>以前重要的</th><th>现在重要的</th></tr></thead><tbody><tr><td>API 记忆能力</td><td>系统设计能力</td></tr><tr><td>快速打字</td><td>清晰表达</td></tr><tr><td>调试技巧</td><td>代码审查技巧</td></tr><tr><td>记住语法细节</td><td>理解架构模式</td></tr><tr><td>知道各种工具命令</td><td>知道什么是对的</td></tr></tbody></table><h3 id="新手到专家的进化路径" tabindex="-1">新手到专家的进化路径 <a class="header-anchor" href="#新手到专家的进化路径" aria-label="Permalink to “新手到专家的进化路径”">​</a></h3><p><strong>第一阶段：使用者</strong></p><ul><li>偶尔提问，让 Claude 解释代码</li><li>让 Claude 写小段代码或简单函数</li><li>自己写大部分代码，Claude 辅助</li></ul><p><strong>第二阶段：协作者</strong></p><ul><li>让 Claude 负责完整的模块开发</li><li>开始使用 Plan Mode 设计方案</li><li>学会写清晰的 CLAUDE.md 和项目约定</li></ul><p><strong>第三阶段：编排者</strong></p><ul><li>Claude 负责 80% 的执行工作</li><li>你负责需求分解、方案设计、质量把关</li><li>建立 Team Skills 和标准化工作流</li><li>多个 Sub-agent 并行完成复杂任务</li></ul><h3 id="哪些能力变得更关键" tabindex="-1">哪些能力变得更关键 <a class="header-anchor" href="#哪些能力变得更关键" aria-label="Permalink to “哪些能力变得更关键”">​</a></h3><ol><li><strong>系统设计能力</strong>：你不需要记住怎么实现，但需要知道什么样的设计是好的</li><li><strong>需求分解能力</strong>：把大需求拆成 Claude 能独立完成的子任务</li><li><strong>代码审查能力</strong>：Claude 写代码很快，判断它的代码写得对不对需要经验</li><li><strong>表达能力</strong>：向 Claude 清晰描述你想要什么，是一门需要练习的技能</li></ol><h2 id="如何有效提问与引导" tabindex="-1">如何有效提问与引导 <a class="header-anchor" href="#如何有效提问与引导" aria-label="Permalink to “如何有效提问与引导”">​</a></h2><h3 id="好-prompt-的特征" tabindex="-1">好 prompt 的特征 <a class="header-anchor" href="#好-prompt-的特征" aria-label="Permalink to “好 prompt 的特征”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>坏 prompt：</span></span>\n<span class="line"><span>&quot;修一下 bug&quot;</span></span>\n<span class="line"><span>&quot;加个功能&quot;</span></span>\n<span class="line"><span>&quot;优化代码&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>好 prompt：</span></span>\n<span class="line"><span>&quot;用户反馈登录后重定向到 404，可能和 URL 拼接有关，</span></span>\n<span class="line"><span> 帮我在 src/auth/ 目录下排查重定向逻辑。&quot;</span></span>\n<span class="line"><span>&quot;给用户列表页添加搜索功能，按用户名模糊匹配，</span></span>\n<span class="line"><span> 参考 src/features/products/SearchBar.tsx 的搜索组件实现。&quot;</span></span>\n<span class="line"><span>&quot;src/utils/dataProcessing.ts 的 transformData 函数有性能问题，</span></span>\n<span class="line"><span> 数据量大时会卡顿，帮我分析瓶颈并优化。&quot;</span></span></code></pre></div><h3 id="三层上下文原则" tabindex="-1">三层上下文原则 <a class="header-anchor" href="#三层上下文原则" aria-label="Permalink to “三层上下文原则”">​</a></h3><p>好的 prompt 包含三个层次的信息：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一层：做什么（What）</span></span>\n<span class="line"><span>第二层：在哪里做（Where）</span></span>\n<span class="line"><span>第三层：怎么做（How，可选）</span></span></code></pre></div><p><strong>第一层只给 What</strong>：让 Claude 自己探索最佳路径</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我找到这段代码的性能瓶颈并优化。</span></span></code></pre></div><p><strong>加 Where</strong>：缩小搜索范围</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我找到 src/services/ 目录下数据处理相关代码的性能瓶颈并优化。</span></span></code></pre></div><p><strong>加 How</strong>：当你有明确的实现偏好</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我找到 src/services/ 下的性能瓶颈，用 memoization 模式优化，</span></span>\n<span class="line"><span> 参考 src/utils/memoize.ts 的实现风格。</span></span></code></pre></div><h3 id="引导而不是命令" tabindex="-1">引导而不是命令 <a class="header-anchor" href="#引导而不是命令" aria-label="Permalink to “引导而不是命令”">​</a></h3><p>Claude Code 擅长安抚你不确定的路径，但你需要给出方向：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>不要：把代码改成 X 方式</span></span>\n<span class="line"><span>更好：代码当前有什么问题？X 方式能否解决？如果可以，请修改</span></span>\n<span class="line"><span>最好：分析当前代码的问题 → Claude 给出诊断 → 你确认 → Claude 修改</span></span></code></pre></div><p>让 Claude <strong>先诊断，后开方</strong>，而不是直接告诉它吃什么药。</p><h2 id="代码质量与所有权" tabindex="-1">代码质量与所有权 <a class="header-anchor" href="#代码质量与所有权" aria-label="Permalink to “代码质量与所有权”">​</a></h2><h3 id="你写的-vs-ai-写的" tabindex="-1">你写的 vs AI 写的 <a class="header-anchor" href="#你写的-vs-ai-写的" aria-label="Permalink to “你写的 vs AI 写的”">​</a></h3><p>使用 Claude Code 后，一个重要的问题浮现：<strong>这是谁的代码？</strong></p><p>答案很简单：<strong>你的。</strong> Claude Code 是工具，你是做出最终决定的人。每当你 accept 一个变更，你就拥有了它。这意味着你对代码负有与手写同等的责任。</p><h3 id="质量控制清单" tabindex="-1">质量控制清单 <a class="header-anchor" href="#质量控制清单" aria-label="Permalink to “质量控制清单”">​</a></h3><p>在 accept Claude 的变更之前，问自己：</p><ul><li>[ ] 我理解这段代码在做什么吗？</li><li>[ ] 它符合项目的代码风格和架构约定吗？</li><li>[ ] 有对应的测试吗？测试覆盖了边界条件吗？</li><li>[ ] 错误处理是否恰当？</li><li>[ ] 有没有引入不必要的依赖？</li><li>[ ] 有没有安全风险（XSS、注入、泄露敏感信息）？</li></ul><p><strong>如果答不上来，不要 accept。</strong> 让 Claude 给你解释，直到你理解为止。</p><h3 id="何时该自己写" tabindex="-1">何时该自己写 <a class="header-anchor" href="#何时该自己写" aria-label="Permalink to “何时该自己写”">​</a></h3><p>有些场景下，亲自动手可能更好：</p><ul><li><strong>学习新技术时</strong>：自己写一遍比看 Claude 写十遍更有效</li><li><strong>业务核心逻辑</strong>：需要你对每一行代码都有深层的理解</li><li><strong>安全敏感代码</strong>：认证、授权、加密等，需要极度审慎</li></ul><h2 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to “局限性”">​</a></h2><h3 id="上下文窗口限制" tabindex="-1">上下文窗口限制 <a class="header-anchor" href="#上下文窗口限制" aria-label="Permalink to “上下文窗口限制”">​</a></h3><p>Claude Code 的上下文窗口约为 200K tokens。对于超大型项目（百万行代码），它无法一次性加载全部项目上下文。</p><p><strong>缓解策略</strong>：</p><ul><li>使用 <code>CLAUDE.md</code> 提供项目高层结构摘要</li><li>在 prompt 中明确指定关注的文件/目录范围</li><li>大型对话及时 <code>/compact</code></li><li>使用 Sub-agent 并行处理不同模块</li></ul><h3 id="理解偏差" tabindex="-1">理解偏差 <a class="header-anchor" href="#理解偏差" aria-label="Permalink to “理解偏差”">​</a></h3><p>Claude Code 可能错误理解你的意图、项目的业务逻辑，或做出不符合实际的假设。</p><p><strong>缓解策略</strong>：</p><ul><li>先让它读代码再下判断</li><li>复杂逻辑让它先口头解释，确认理解正确再编码</li><li>发现理解偏差时明确纠正，让它记住</li></ul><h3 id="代码一致性" tabindex="-1">代码一致性 <a class="header-anchor" href="#代码一致性" aria-label="Permalink to “代码一致性”">​</a></h3><p>在大型项目中，Claude 可能在不同文件中使用不一致的实现风格。</p><p><strong>缓解策略</strong>：</p><ul><li><code>CLAUDE.md</code> 中写清楚编码规范</li><li>使用 Skills 封装团队标准工作流</li><li>代码审查时注意一致性检查</li></ul><h3 id="安全与隐私" tabindex="-1">安全与隐私 <a class="header-anchor" href="#安全与隐私" aria-label="Permalink to “安全与隐私”">​</a></h3><p>Claude Code 会将代码发送到 Anthropic 的服务器进行处理。这意味着：</p><ul><li><strong>不应在未授权的情况下使用</strong>：遵守公司的 AI 工具使用政策</li><li><strong>敏感代码需要额外注意</strong>：不要在对话中包含密钥、证书、内部系统架构等</li><li><strong>数据驻留</strong>：了解你的数据的处理位置和保留策略</li></ul><h3 id="成本管理" tabindex="-1">成本管理 <a class="header-anchor" href="#成本管理" aria-label="Permalink to “成本管理”">​</a></h3><p>使用 API Key 时，每次对话都有成本：</p><ul><li><strong>Sonnet 4.6</strong>：适合大多数任务，性价比最高</li><li><strong>Opus 4.7</strong>：显著更贵，仅在复杂任务时使用</li><li><strong>Haiku 4.5</strong>：最经济，用于简单查询</li></ul><p><strong>省钱技巧</strong>：</p><ul><li>用 cc-switch 按需切换模型</li><li>保持对话简洁，及时 <code>/clear</code> 或 <code>/compact</code></li><li>不要用 Opus 做 Haiku 能做的事</li></ul><h3 id="不适合的场景" tabindex="-1">不适合的场景 <a class="header-anchor" href="#不适合的场景" aria-label="Permalink to “不适合的场景”">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>原因</th></tr></thead><tbody><tr><td>实时性能调优</td><td>需要反复测量和微调，Claude 无法直接感知运行态性能</td></tr><tr><td>需要视觉判断的 UI 开发</td><td>Claude 看不到渲染结果</td></tr><tr><td>高度受监管的行业代码</td><td>合规性要求可能不允许 AI 生成代码</td></tr><tr><td>需要大量领域知识的专业系统</td><td>Claude 的领域知识可能不够深入</td></tr><tr><td>一次性的 hack 脚本（探索阶段）</td><td>自己写更快，等 Claude 理解完你已经写好了</td></tr></tbody></table>',65))])}]]);export{r as __pageData,o as default};
